def solve(resolutions, target_aspect_ratio):
    def aspect_ratio(width, height):
        return width / height

    def is_valid_resolution(width, height):
        return aspect_ratio(width, height) == target_aspect_ratio

    valid_resolutions = [res for res in resolutions if is_valid_resolution(*res)]

    return valid_resolutions if valid_resolutions else None
